Now it's just a matter of configuration differences or getting the needed fix(es) in your setup.  This is the conflist I used.

```
{
   "cniVersion":"0.4.0",
   "name":"test-network",
   "plugins":[
      {
         "type":"bridge",
         "bridge":"test-network",
         "isGateway":true,
         "ipMasq":true,
         "hairpinMode":true,
         "ipam":{
            "type":"host-local",
            "ranges":[
               [
                  {
                     "subnet":"10.66.2.0/24"
                  }
               ]
            ],
            "routes":[
               {
                  "dst":"0.0.0.0/0"
               }
            ]
         }
      },
      {
         "name":"myfirewall",
         "type":"firewall",
         "backend":"iptables"
      },
      {
         "type":"tuning",
         "capabilities":{
            "mac":true
         }
      },
      {
         "type":"portmap",
         "capabilities":{
            "portMappings":true
         }
      }
   ]
}


```

Also, diff your podman network conflist  vs.  test-network  to see anything other than e.g. subnet, bridge name etc. that might stand out.

